import { existsSync, readFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import { spawnSync } from 'node:child_process';
import { appendFileEntry, finalizeLock, loadLock } from '../config/lock.js';
import type { LockFileEntry } from '../config/schema.js';
import { hashString } from '../utils/hash.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

function getKdocRoot(): string {
  // After tsup bundling, __dirname is cli/dist/. Navigate: dist/ → cli/ → kdoc/
  // In source (vitest), __dirname is cli/src/integrations/. Navigate: integrations/ → src/ → cli/ → kdoc/
  // Try bundled path first (2 levels), fall back to source path (3 levels).
  const bundledPath = join(__dirname, '..', '..');
  if (existsSync(join(bundledPath, 'integrations'))) return bundledPath;
  return join(__dirname, '..', '..', '..');
}

export interface ToolInstallManifest {
  created: string[];
  merged: string[];
  skipped: string[];
}

export interface ToolInstallResult {
  ok: boolean;
  fallbackUsed: boolean;
  manifest: ToolInstallManifest;
  stdout: string;
  stderr: string;
  warnings: string[];
}

function normalizeManifest(value: unknown): ToolInstallManifest | null {
  if (!value || typeof value !== 'object' || Array.isArray(value)) return null;

  const record = value as Record<string, unknown>;
  const readStringArray = (key: string): string[] => {
    const raw = record[key];
    return Array.isArray(raw) ? raw.filter((entry): entry is string => typeof entry === 'string') : [];
  };

  return {
    created: readStringArray('created'),
    merged: readStringArray('merged'),
    skipped: readStringArray('skipped'),
  };
}

function installerPathFor(tool: string): string {
  return join(getKdocRoot(), 'integrations', tool, 'install.js');
}

function readInstalledContent(projectDir: string, relativePath: string): string | null {
  const absolutePath = join(projectDir, relativePath);
  if (!existsSync(absolutePath)) return null;

  try {
    return readFileSync(absolutePath, 'utf8');
  } catch {
    return null;
  }
}

function trackInstallerManifest(projectDir: string, manifest: ToolInstallManifest): void {
  const lock = loadLock(projectDir);
  if (!lock) return;

  for (const relativePath of manifest.created) {
    if (lock.files[relativePath]) continue;

    const content = readInstalledContent(projectDir, relativePath);
    if (content === null) continue;

    const fileHash = hashString(content);
    const entry: LockFileEntry = {
      action: 'created',
      hash: fileHash,
      templateHash: fileHash,
      template: `tool-installed:${relativePath}`,
    };
    appendFileEntry(projectDir, lock, relativePath, entry);
  }

  finalizeLock(projectDir);
}

export function runToolInstaller(
  tool: string,
  projectDir: string,
  options: { dryRun?: boolean; yes?: boolean } = {},
): ToolInstallResult {
  const installerPath = installerPathFor(tool);
  const manifest: ToolInstallManifest = { created: [], merged: [], skipped: [] };
  const warnings: string[] = [];

  if (!existsSync(installerPath)) {
    warnings.push(`Installer missing for tool "${tool}" at ${installerPath}; kept scaffold-only fallback.`);
    return {
      ok: true,
      fallbackUsed: true,
      manifest,
      stdout: '',
      stderr: '',
      warnings,
    };
  }

  const args = [
    installerPath,
    '--project-root',
    projectDir,
    '--kdoc-root',
    getKdocRoot(),
    '--manifest',
  ];

  if (options.dryRun) args.push('--dry-run');
  if (options.yes) args.push('--yes');

  const result = spawnSync('node', args, {
    cwd: projectDir,
    encoding: 'utf8',
  });

  const stdout = result.stdout ?? '';
  const stderr = result.stderr ?? '';

  if (result.status !== 0) {
    warnings.push(`Installer for tool "${tool}" exited with code ${result.status}; kept scaffold-only fallback.`);
    return {
      ok: false,
      fallbackUsed: true,
      manifest,
      stdout,
      stderr,
      warnings,
    };
  }

  const parsed = normalizeManifest((() => {
    try {
      return JSON.parse(stdout.trim() || '{}');
    } catch {
      return null;
    }
  })());

  if (!parsed) {
    warnings.push(`Installer for tool "${tool}" did not return a manifest; kept scaffold-only fallback.`);
    return {
      ok: true,
      fallbackUsed: true,
      manifest,
      stdout,
      stderr,
      warnings,
    };
  }

  if (!options.dryRun) {
    trackInstallerManifest(projectDir, parsed);
  }

  return {
    ok: true,
    fallbackUsed: false,
    manifest: parsed,
    stdout,
    stderr,
    warnings,
  };
}
