import { Command } from 'commander';
import { execFileSync } from 'node:child_process';
import { join } from 'node:path';
import { loadConfig } from '../config/loader.js';
import { safeWriteFile } from '../utils/fs.js';
import { assembleBrief, parseKnowledgeDocs, resolveDocumentTree, resolveReference, writeKnowledgeJsonl } from '../compiler/index.js';
import { resolveRoadmapStatus } from '../roadmap/status.js';

function getProjectDir(): string {
  return process.env.KDOC_PROJECT_DIR ?? process.cwd();
}

function resolveSeedDoc(
  docs: ReturnType<typeof parseKnowledgeDocs>,
  options: { subPhase?: string; tldr?: string; next?: boolean },
  projectDir: string,
  knowledgeRoot: string,
) {
  if (options.subPhase) {
    return resolveReference(options.subPhase, docs);
  }

  if (options.tldr) {
    return docs.find(
      (doc) =>
        doc.type === 'tldr' &&
        (doc.path.toLowerCase().includes(options.tldr!.toLowerCase()) ||
          String(doc.frontmatter.title ?? '').toLowerCase() === options.tldr!.toLowerCase()),
    ) ?? resolveReference(options.tldr, docs);
  }

  if (options.next) {
    const roadmapStatus = resolveRoadmapStatus(join(projectDir, knowledgeRoot, 'Roadmap'));
    if (roadmapStatus.next) return resolveReference(roadmapStatus.next.subPhase.id, docs);
  }

  return null;
}

function writeClipboard(content: string): void {
  execFileSync('pbcopy', { input: content });
}

export function registerBriefCommand(program: Command): void {
  const cmd = new Command('brief');

  cmd
    .description('Compile an implementation-ready Knowledge brief')
    .option('--sub-phase <id>', 'Generate a brief for a roadmap sub-phase')
    .option('--tldr <name>', 'Generate a brief for a TLDR document')
    .option('--next', 'Generate a brief for the next unblocked roadmap sub-phase')
    .option('--format <format>', 'markdown|json|clipboard', 'markdown')
    .option('--output <path>', 'Write the brief to a file')
    .option('--depth <n>', 'Graph resolution depth', '2')
    .option('--yes', 'Non-interactive mode')
    .action((options) => {
      const projectDir = getProjectDir();
      const config = loadConfig(projectDir);
      if (!config) {
        console.error('Error: .kdoc.yaml not found. Run `kdoc init` first.');
        process.exitCode = 1;
        return;
      }

      const targetCount = [options.subPhase, options.tldr, options.next].filter(Boolean).length;
      if (targetCount !== 1) {
        console.error('Error: choose exactly one of --sub-phase, --tldr, or --next.');
        process.exitCode = 1;
        return;
      }

      const knowledgeRoot = config.root ?? 'Knowledge';
      const docs = parseKnowledgeDocs(projectDir, knowledgeRoot);
      writeKnowledgeJsonl(projectDir, docs, knowledgeRoot);

      const seed = resolveSeedDoc(docs, options, projectDir, knowledgeRoot);
      if (!seed) {
        console.error('Error: could not resolve the requested Knowledge target.');
        process.exitCode = 1;
        return;
      }

      const depth = Number.parseInt(String(options.depth ?? '2'), 10);
      const resolved = resolveDocumentTree(seed, docs, Number.isNaN(depth) ? 2 : depth);
      const brief = assembleBrief(seed, resolved, docs);

      let output = brief.markdown;
      if (options.format === 'json') {
        output = JSON.stringify(
          {
            target: seed.path,
            coverage: brief.coverage,
            markdown: brief.markdown,
          },
          null,
          2,
        );
      } else if (options.format === 'clipboard') {
        try {
          writeClipboard(brief.markdown);
          output = 'Copied brief to clipboard.\n';
        } catch {
          output = brief.markdown;
        }
      }

      if (options.output) {
        safeWriteFile(options.output, brief.markdown);
      }

      if (!options.output || options.format !== 'clipboard') {
        process.stdout.write(output.endsWith('\n') ? output : `${output}\n`);
      }
    });

  program.addCommand(cmd);
}
