import { existsSync, readFileSync, copyFileSync, readdirSync } from 'node:fs';
import { join, dirname, basename } from 'node:path';
import type { KdocConfig, LockFileEntry } from '../config/schema.js';
import type { FileOperation, ExecutionSummary } from './types.js';
import { safeWriteFile, ensureDir } from '../utils/fs.js';
import { hashString } from '../utils/hash.js';
import { createEmptyLock, loadLock, appendFileEntry, finalizeLock } from '../config/lock.js';
import { injectMarkerBlock } from './merge/markers.js';
import { mergePackageJsonScripts } from './merge/package-json.js';
import { mergeTurboJsonTasks } from './merge/turbo-json.js';
import { renderTemplate } from '../templates/renderer.js';
import { getGitOwner } from '../utils/git.js';

export interface ExecutorOptions {
  operations: FileOperation[];
  config: KdocConfig;
  projectDir: string;
  kdocVersion: string;
  /** Rendered template content keyed by source path */
  templateContents: Map<string, string>;
  dryRun?: boolean;
  verbose?: boolean;
  /** When true, overwrite user-modified managed files (CONFLICT → overwrite) */
  force?: boolean;
  onProgress?: (op: FileOperation, result: 'done' | 'skipped' | 'conflict' | 'error') => void;
}

function backupFile(projectDir: string, relativePath: string): void {
  const absSource = join(projectDir, relativePath);
  const absDest = join(projectDir, '.kdoc.backup', relativePath);
  if (!existsSync(absSource)) return;
  if (existsSync(absDest)) return; // Only backup once — preserve pre-kdoc state
  ensureDir(dirname(absDest));
  copyFileSync(absSource, absDest);
}

async function applyMerge(
  op: FileOperation,
  projectDir: string,
  templateContent: string,
): Promise<string> {
  const absPath = join(projectDir, op.path);
  const fileName = op.path.split('/').pop() ?? op.path;
  const existing = existsSync(absPath) ? readFileSync(absPath, 'utf8') : '';

  if (op.mergeStrategy === 'markers') {
    return injectMarkerBlock(existing, templateContent, fileName, op.markerName ?? 'core');
  }

  if (op.mergeStrategy === 'prefix') {
    if (fileName === 'package.json') {
      // templateContent is a JSON string of scripts Record<string, string>
      let scripts: Record<string, string>;
      try {
        scripts = JSON.parse(templateContent) as Record<string, string>;
      } catch {
        scripts = {};
      }
      // If existing file has no content, create a minimal package.json
      const existingContent = existing || '{}';
      return mergePackageJsonScripts(existingContent, scripts);
    }
    if (fileName === 'turbo.json') {
      // templateContent is a JSON string of tasks Record<string, object>
      let tasks: Record<string, object>;
      try {
        tasks = JSON.parse(templateContent) as Record<string, object>;
      } catch {
        tasks = {};
      }
      const existingContent = existing || '{}';
      return mergeTurboJsonTasks(existingContent, tasks);
    }
  }

  // Fallback: append (should not reach here with valid operations)
  return existing + '\n' + templateContent;
}

function resolveAdrNextSequence(projectDir: string, _config: KdocConfig, scopePath: string): string {
  const adrDir = join(projectDir, scopePath, 'ADR');
  if (!existsSync(adrDir)) return '0001';
  const entries = readdirSync(adrDir);
  const numbers = entries
    .map((f: string) => {
      const match = f.match(/^ADR-(\d{4})-/);
      return match ? parseInt(match[1], 10) : 0;
    })
    .filter((n: number) => n > 0);
  const max = numbers.length > 0 ? Math.max(...numbers) : 0;
  return String(max + 1).padStart(4, '0');
}

function buildRenderValues(
  op: FileOperation,
  config: KdocConfig,
  projectDir: string,
): Record<string, string> {
  const rootName = config.root ?? 'Knowledge';
  const segments = op.path.replaceAll('\\', '/').split('/');
  const values: Record<string, string> = {};

  // Scope detection
  let scopePath = rootName;
  if (segments[0] === rootName && segments[1] === 'packages' && segments[2]) {
    values.SCOPE = segments[2];
    scopePath = join(rootName, 'packages', segments[2]);
  } else if (config.topology === 'vault' && segments[0] === rootName && segments[1]) {
    values.SCOPE = segments[1];
    values.CATEGORY_NAME = segments[1];
    values.CATEGORY_LABEL = config.categories?.[segments[1]]?.label ?? segments[1];
  } else {
    values.SCOPE = 'root';
  }

  // Standard values
  values.PROJECT_NAME = basename(projectDir) || 'project';
  values.KNOWLEDGE_ROOT = rootName;
  values.DATE = new Date().toISOString().slice(0, 10);

  // Owner from git — fallback to empty string (non-git repos)
  const owner = getGitOwner(projectDir);
  if (owner) {
    values.OWNER = owner;
  }

  // ADR sequence
  values.ADR_NEXT_SEQUENCE = resolveAdrNextSequence(projectDir, config, scopePath);

  // Wikilink prefix for cross-references
  if (values.SCOPE === 'root') {
    values.WIKILINK_PREFIX = '';
  } else if (segments[0] === rootName && segments[1] === 'packages' && segments[2]) {
    values.WIKILINK_PREFIX = `packages/${segments[2]}/`;
  } else {
    values.WIKILINK_PREFIX = '';
  }

  return values;
}

function renderScaffoldTemplate(
  op: FileOperation,
  templateContent: string,
  config: KdocConfig,
  projectDir: string,
): string {
  if (!templateContent.includes('{{')) return templateContent;

  const values = buildRenderValues(op, config, projectDir);
  return renderTemplate(templateContent, values).content;
}

export async function executeScaffold(options: ExecutorOptions): Promise<ExecutionSummary> {
  const {
    operations,
    config,
    projectDir,
    kdocVersion,
    templateContents,
    dryRun = false,
    force = false,
    onProgress,
  } = options;

  const summary: ExecutionSummary = {
    created: [],
    merged: [],
    updated: [],
    removed: [],
    renamed: [],
    skipped: [],
    conflicts: [],
    errors: [],
  };

  const lockConfig = {
    root: config.root ?? 'Knowledge',
    packs: config.packs ?? [],
    tools: config.tools ?? [],
    ...(config.topology ? { topology: config.topology } : {}),
    ...(config.packages ? { packages: Object.fromEntries(
      Object.entries(config.packages).map(([name, packageConfig]) => [name, { path: packageConfig.path }]),
    ) } : {}),
  };

  // Merge into existing lock to preserve entries from earlier add-* / init runs
  const existingLock = loadLock(projectDir);
  const lock = existingLock
    ? { ...existingLock, kdocVersion, config: lockConfig, files: { ...existingLock.files } }
    : createEmptyLock(kdocVersion, lockConfig);

  for (const op of operations) {
    try {
      if (op.type === 'SKIP') {
        summary.skipped.push(op.path);
        onProgress?.(op, 'skipped');
        continue;
      }

      if (op.type === 'CONFLICT') {
        if (!force) {
          summary.conflicts.push(op.path);
          onProgress?.(op, 'conflict');
          continue;
        }
        // --force: render template before writing (same as CREATE path)
        const renderedContent = renderScaffoldTemplate(
          op,
          templateContents.get(op.source) ?? '',
          config,
          projectDir,
        );
        if (!dryRun) {
          backupFile(projectDir, op.path);
          safeWriteFile(join(projectDir, op.path), renderedContent);
          const fileHash = hashString(renderedContent);
          const templateHash = hashString(templateContents.get(op.source) ?? '');
          const entry: LockFileEntry = {
            action: 'created',
            hash: fileHash,
            templateHash,
            template: op.source,
          };
          appendFileEntry(projectDir, lock, op.path, entry);
        }
        summary.created.push(op.path);
        onProgress?.(op, 'done');
        continue;
      }

      const templateContent = renderScaffoldTemplate(
        op,
        templateContents.get(op.source) ?? '',
        config,
        projectDir,
      );

      if (op.type === 'CREATE') {
        if (!dryRun) {
          safeWriteFile(join(projectDir, op.path), templateContent);
          const fileHash = hashString(templateContent);
          const templateHash = hashString(templateContent);
          const entry: LockFileEntry = {
            action: 'created',
            hash: fileHash,
            templateHash,
            template: op.source,
          };
          appendFileEntry(projectDir, lock, op.path, entry);
        }
        summary.created.push(op.path);
        onProgress?.(op, 'done');
        continue;
      }

      if (op.type === 'MERGE') {
        if (!dryRun) {
          backupFile(projectDir, op.path);
          const merged = await applyMerge(op, projectDir, templateContent);
          safeWriteFile(join(projectDir, op.path), merged);

          const blockHash = hashString(templateContent);
          const templateHash = hashString(templateContent);
          const entry: LockFileEntry = {
            action: 'merged',
            blockHash,
            templateHash,
            template: op.source,
            strategy: op.mergeStrategy ?? 'markers',
            ...(op.markerName ? { markerName: op.markerName } : {}),
          };
          appendFileEntry(projectDir, lock, op.path, entry);
        }
        summary.merged.push(op.path);
        onProgress?.(op, 'done');
        continue;
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      summary.errors.push({ path: op.path, error: message });
      onProgress?.(op, 'error');
    }
  }

  // Finalize: rename .kdoc.lock.tmp → .kdoc.lock
  if (!dryRun) {
    finalizeLock(projectDir);
  }

  return summary;
}
