import type { Constraint, ParsedKnowledgeDoc } from './index.js';

const KEYWORDS = ['MUST NOT', 'SHOULD NOT', 'MUST', 'SHALL', 'SHOULD'] as const;
type Keyword = (typeof KEYWORDS)[number];

function normalizeConstraintLine(line: string): string {
  return line
    .replace(/^[-*]\s+/, '')
    .replace(/^\d+\.\s+/, '')
    .trim();
}

export function extractConstraints(docs: ParsedKnowledgeDoc[]): Constraint[] {
  const constraints: Constraint[] = [];

  for (const doc of docs) {
    if (doc.type !== 'adr') continue;

    const lines = doc.body.split('\n');
    for (const line of lines) {
      const normalized = normalizeConstraintLine(line);
      if (!normalized) continue;

      const keyword = KEYWORDS.find((item) =>
        new RegExp(`\\b${item.replace(/\s+/g, '\\s+')}\\b`, 'i').test(normalized),
      );

      if (!keyword) continue;

      constraints.push({
        source: doc.path,
        keyword: keyword as Keyword,
        ruleText: normalized,
      });
    }
  }

  return constraints;
}
