import type { ParsedKnowledgeDoc, ResolvedNode } from './index.js';

type ResolverIndex = Map<string, ParsedKnowledgeDoc>;

function normalizeReference(raw: string): string {
  return raw
    .trim()
    .replace(/^\[\[|\]\]$/g, '')
    .split('|')[0]
    .split('#')[0]
    .replace(/^Knowledge\//, '')
    .replace(/^\.?\//, '')
    .replace(/\.md$/i, '')
    .trim()
    .toLowerCase();
}

function looksLikeReference(value: string): boolean {
  const trimmed = value.trim();
  return (
    trimmed.includes('/') ||
    /^ADR-\d+/i.test(trimmed) ||
    /^phase-[\w.-]+$/i.test(trimmed) ||
    /^\d+(?:\.\d+)*$/.test(trimmed)
  );
}

function collectFrontmatterReferences(frontmatter: Record<string, unknown>): string[] {
  const refs = new Set<string>();

  const visit = (value: unknown): void => {
    if (typeof value === 'string') {
      if (looksLikeReference(value)) refs.add(value);
      return;
    }
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
    }
  };

  for (const [key, value] of Object.entries(frontmatter)) {
    if (/(^|_)(tldr|design|adr|blocked|depends|related|supersed|phase|parallel|guide|runbook|context|used)(_|\b)/i.test(key)) {
      visit(value);
    }
  }

  return [...refs];
}

function docIndexKeys(doc: ParsedKnowledgeDoc): string[] {
  const keys = new Set<string>();
  keys.add(normalizeReference(doc.path));
  keys.add(normalizeReference(doc.path.replace(/\.md$/i, '')));

  const basename = doc.path.split('/').pop() ?? doc.path;
  keys.add(normalizeReference(basename));
  keys.add(normalizeReference(basename.replace(/\.md$/i, '')));

  if (typeof doc.frontmatter.id === 'string') keys.add(normalizeReference(doc.frontmatter.id));
  if (typeof doc.frontmatter.title === 'string') keys.add(normalizeReference(doc.frontmatter.title));
  for (const alias of Array.isArray(doc.frontmatter.aliases) ? doc.frontmatter.aliases : []) {
    if (typeof alias === 'string') keys.add(normalizeReference(alias));
  }

  return [...keys].filter(Boolean);
}

export function buildResolverIndex(docs: ParsedKnowledgeDoc[]): ResolverIndex {
  const index: ResolverIndex = new Map();
  for (const doc of docs) {
    for (const key of docIndexKeys(doc)) {
      if (!index.has(key)) index.set(key, doc);
    }
  }
  return index;
}

export function resolveReference(
  reference: string,
  docsOrIndex: ParsedKnowledgeDoc[] | ResolverIndex,
): ParsedKnowledgeDoc | null {
  const index = docsOrIndex instanceof Map ? docsOrIndex : buildResolverIndex(docsOrIndex);
  return index.get(normalizeReference(reference)) ?? null;
}

export function resolveDocumentTree(
  seed: ParsedKnowledgeDoc,
  docs: ParsedKnowledgeDoc[],
  depth = 2,
): ResolvedNode {
  const index = buildResolverIndex(docs);
  const visited = new Set<string>();

  const walk = (doc: ParsedKnowledgeDoc, remainingDepth: number): ResolvedNode => {
    visited.add(doc.path);
    const references = [...new Set([...doc.wikilinks, ...collectFrontmatterReferences(doc.frontmatter)])];
    const children: ResolvedNode[] = [];
    const missing: string[] = [];

    if (remainingDepth > 0) {
      for (const reference of references) {
        const resolved = resolveReference(reference, index);
        if (!resolved) {
          missing.push(reference);
          continue;
        }
        if (visited.has(resolved.path)) continue;
        children.push(walk(resolved, remainingDepth - 1));
      }
    } else {
      for (const reference of references) {
        if (!resolveReference(reference, index)) missing.push(reference);
      }
    }

    return { doc, references, children, missing };
  };

  return walk(seed, depth);
}

export function collectResolvedDocs(root: ResolvedNode): ParsedKnowledgeDoc[] {
  const docs = new Map<string, ParsedKnowledgeDoc>();
  const stack = [root];

  while (stack.length > 0) {
    const node = stack.pop()!;
    docs.set(node.doc.path, node.doc);
    for (const child of node.children) stack.push(child);
  }

  return [...docs.values()];
}
