import { Command } from 'commander';
import { join } from 'node:path';
import { existsSync } from 'node:fs';
import { loadConfig } from '../config/loader.js';
import { parseRoadmap } from '../roadmap/parser.js';
import { buildDependencyGraph, getExecutionWaves } from '../roadmap/graph.js';
import { generateDashboardContent, writeDashboard } from '../roadmap/dashboard.js';
import { getNextUnblocked, formatNextAsMarkdown, formatNextAsJson } from '../roadmap/next.js';

function getProjectDir(): string {
  return process.env.KDOC_PROJECT_DIR ?? process.cwd();
}

export function registerRoadmapCommand(program: Command): void {
  const roadmap = new Command('roadmap');
  roadmap.description('Roadmap dependency graph, dashboard, and next-step queries');

  // kdoc roadmap dashboard
  roadmap
    .command('dashboard')
    .description('Generate or update the roadmap progress dashboard')
    .option('--yes', 'Non-interactive mode')
    .action(async () => {
      const projectDir = getProjectDir();
      const config = loadConfig(projectDir);
      if (!config) {
        console.error('Error: .kdoc.yaml not found. Run `kdoc init` first.');
        process.exitCode = 2;
        return;
      }

      const roadmapDir = join(projectDir, config.root, 'Roadmap');
      if (!existsSync(roadmapDir)) {
        console.error(`Error: Roadmap directory not found at ${config.root}/Roadmap/`);
        process.exitCode = 1;
        return;
      }

      try {
        const phases = parseRoadmap(roadmapDir);
        if (phases.length === 0) {
          console.log('No phases found in Roadmap/phases/.');
          return;
        }

        const graph = buildDependencyGraph(phases);
        const content = generateDashboardContent(phases, graph);
        const readmePath = join(roadmapDir, 'README.md');
        writeDashboard(readmePath, content);
        console.log(`Dashboard updated: ${config.root}/Roadmap/README.md`);
        console.log(`  ${phases.length} phase(s), ${phases.reduce((n, p) => n + p.subPhases.length, 0)} sub-phase(s)`);
      } catch (err) {
        console.error(`Error: ${err instanceof Error ? err.message : String(err)}`);
        process.exitCode = 1;
      }
    });

  // kdoc roadmap next
  roadmap
    .command('next')
    .description('Show the next unblocked sub-phase with full context')
    .option('--json', 'Output as JSON')
    .option('--all', 'Show all unblocked items, not just the first')
    .option('--yes', 'Non-interactive mode')
    .action(async (opts: { json?: boolean; all?: boolean }) => {
      const projectDir = getProjectDir();
      const config = loadConfig(projectDir);
      if (!config) {
        console.error('Error: .kdoc.yaml not found. Run `kdoc init` first.');
        process.exitCode = 2;
        return;
      }

      const roadmapDir = join(projectDir, config.root, 'Roadmap');
      if (!existsSync(roadmapDir)) {
        console.error(`Error: Roadmap directory not found at ${config.root}/Roadmap/`);
        process.exitCode = 1;
        return;
      }

      try {
        const phases = parseRoadmap(roadmapDir);
        if (phases.length === 0) {
          console.log('No phases found in Roadmap/phases/.');
          return;
        }

        const graph = buildDependencyGraph(phases);
        const results = getNextUnblocked(phases, graph);

        if (results.length === 0) {
          console.log('All sub-phases are completed or blocked. Nothing to do next.');
          return;
        }

        if (opts.json) {
          const items = opts.all ? results : [results[0]];
          console.log(formatNextAsJson(items));
        } else {
          const items = opts.all ? results : [results[0]];
          for (const item of items) {
            console.log(formatNextAsMarkdown(item));
          }
        }
      } catch (err) {
        console.error(`Error: ${err instanceof Error ? err.message : String(err)}`);
        process.exitCode = 1;
      }
    });

  program.addCommand(roadmap);
}
