const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

// ---- Desired-State Types ----

export interface DesiredEntry {
  /** Which source template produced this file (stable identity key). */
  template: string;
  /** SHA-256 hash of the source template in the running kdoc version. */
  currentTemplateHash: string;
  /**
   * SHA-256 hash of the actual file on disk (for created entries).
   * Absent means: caller didn't read the file (will be treated as missing/unknown).
   */
  currentFileHash?: string;
}

export type DesiredStateManifest = Record<string, DesiredEntry>;

// ---- Diff Operation Types ----

export type DiffOperation =
  | { type: 'SKIP'; path: string }
  | { type: 'CREATE'; path: string; template: string }
  | { type: 'UPDATE'; path: string; template: string; userModified: boolean }
  | { type: 'REMOVE'; path: string; userModified: boolean }
  | { type: 'RENAME'; oldPath: string; newPath: string; template: string; userModified: boolean };

// ---- Synthetic Templates ----

const SYNTHETIC_TEMPLATES: Record<string, string> = {
  'core/templates/gitkeep': '',
  'core/templates/claude-md-block.md':
    'kdoc Knowledge documentation toolkit is installed.\n\nRun `npx kdoc doctor` to check your setup.\n',
  'core/templates/agents-md-block.md':
    'kdoc Knowledge documentation toolkit is installed.\n\nRun `npx kdoc doctor` to check your setup.\n',
  'core/templates/gitignore-block': '.kdoc.backup/\n.kdoc.lock.tmp\n',
  'core/templates/package-json-scripts': JSON.stringify({ 'kdoc:check': 'npx kdoc doctor' }),
};

// ---- Template Resolver ----

function makeUpdateTemplateResolver(): (templateName: string) => { sourcePath: string; content: string } | null {
  const cliRoot = join(__dirname, '..', '..');
  const kdocRoot = join(cliRoot, '..');
  const coreTemplatesDir = join(kdocRoot, 'core', 'templates');
  const packsDir = join(kdocRoot, 'packs');

  return (templateName: string) => {
    if (templateName in SYNTHETIC_TEMPLATES) {
      return { sourcePath: templateName, content: SYNTHETIC_TEMPLATES[templateName] };
    }

    if (templateName.startsWith('core/templates/')) {
      const relFile = templateName.slice('core/templates/'.length);
      const filePath = join(coreTemplatesDir, relFile);
      if (existsSync(filePath)) {
        return { sourcePath: templateName, content: readFileSync(filePath, 'utf8') };
      }
      return null;
    }

    const packsMatch = templateName.match(/^packs\/([^/]+)\/templates\/(.+)$/);
    if (packsMatch) {
      const [, packName, relFile] = packsMatch;
      const filePath = join(packsDir, packName, 'templates', relFile);
      if (existsSync(filePath)) {
        return { sourcePath: templateName, content: readFileSync(filePath, 'utf8') };
      }
      return null;
    }

    return null;
  };
}

// ---- Desired File Derivation ----

interface DesiredFile {
  path: string;
  templateName: string;
}

/**
 * Derive the list of files that SHOULD exist given the current config.
 * Topology-aware: enumerates root + packages (monorepo) or root + categories (vault).
 *
 * Bug 3 fix: Previously only enumerated root areas, causing package/vault docs
 * to be marked as REMOVE. Now includes per-package and per-category files.
 */
function deriveDesiredFiles(config: KdocConfig): DesiredFile[] {
  const files: DesiredFile[] = [];
  const root = config.root ?? 'Knowledge';
  const areas = config.areas ?? {};

  // Enumerate area files for a given Knowledge root prefix
  function addAreaFiles(prefix: string, scopeAreas: Record<string, { enabled: boolean; scopes?: string[] }>) {
    if (scopeAreas['adr']?.enabled) {
      files.push({ path: `${prefix}/ADR/README.md`, templateName: 'core/templates/readme-adr.md' });
    }
    if (scopeAreas['tldr']?.enabled) {
      files.push({ path: `${prefix}/TLDR/README.md`, templateName: 'core/templates/readme-tldr.md' });
      for (const scope of (scopeAreas['tldr'].scopes ?? [])) {
        files.push({ path: `${prefix}/TLDR/${scope}/.gitkeep`, templateName: 'core/templates/gitkeep' });
      }
    }
    if (scopeAreas['roadmap']?.enabled) {
      files.push({ path: `${prefix}/Roadmap/README.md`, templateName: 'core/templates/readme-roadmap.md' });
    }
    if (scopeAreas['context-pack']?.enabled) {
      files.push({ path: `${prefix}/ContextPack.md`, templateName: 'core/templates/context-pack.md' });
    }
    if (scopeAreas['agent-memory']?.enabled) {
      files.push({ path: `${prefix}/AgentMemory/MEMORY.md`, templateName: 'core/templates/memory.md' });
    }
    if (scopeAreas['guides']?.enabled) {
      files.push({ path: `${prefix}/Guides/.gitkeep`, templateName: 'core/templates/gitkeep' });
    }
    if (scopeAreas['runbooks']?.enabled) {
      files.push({ path: `${prefix}/runbooks/.gitkeep`, templateName: 'core/templates/gitkeep' });
    }
    if (scopeAreas['templates']?.enabled) {
      files.push({ path: `${prefix}/Templates/.gitkeep`, templateName: 'core/templates/gitkeep' });
    }
  }

  // Root scope
  addAreaFiles(root, areas);

  // Monorepo: per-package files (per R1: Knowledge/packages/<name>/)
  if (config.topology === 'monorepo' && config.packages) {
    for (const [pkgName, pkgConfig] of Object.entries(config.packages)) {
      const pkgAreas = pkgConfig.areas ?? areas; // inherit root areas if not overridden
      addAreaFiles(`${root}/packages/${pkgName}`, pkgAreas);
    }
  }

  // Vault: per-category directories
  if (config.topology === 'vault' && config.categories) {
    for (const [catName] of Object.entries(config.categories)) {
      files.push({ path: `${root}/${catName}/README.md`, templateName: 'core/templates/readme-category.md' });
    }
  }

  // Tool integrations (root-level only)
  for (const tool of config.tools ?? []) {
    if (tool === 'claude-code') {
      files.push({ path: 'CLAUDE.md', templateName: 'core/templates/claude-md-block.md' });
    }
    if (tool === 'codex') {
      files.push({ path: 'AGENTS.md', templateName: 'core/templates/agents-md-block.md' });
    }
  }

  files.push({ path: '.gitignore', templateName: 'core/templates/gitignore-block' });
  files.push({ path: 'package.json', templateName: 'core/templates/package-json-scripts' });

  return files;
}

// ---- Build Desired State ----

/**
 * Build a DesiredStateManifest from config and current kdoc templates.
 * Computes template hashes and reads current file hashes from disk.
 */
export function buildDesiredState(
  config: KdocConfig,
  projectDir: string,
  templateResolver?: (templateName: string) => { sourcePath: string; content: string } | null,
): DesiredStateManifest {
  const resolver = templateResolver ?? makeUpdateTemplateResolver();
  const desired = deriveDesiredFiles(config);
  const manifest: DesiredStateManifest = {};

  for (const { path, templateName } of desired) {
    const resolved = resolver(templateName);
    if (!resolved) continue;

    const currentTemplateHash = hashString(resolved.content);
    const absPath = join(projectDir, path);

    let currentFileHash: string | undefined;
    if (existsSync(absPath)) {
      try {
        currentFileHash = hashFile(absPath);
      } catch {
        // File unreadable — leave as undefined
      }
    }

    manifest[path] = {
      template: templateName,
      currentTemplateHash,
      currentFileHash,
    };
  }

  return manifest;
}

// ---- Diff ----

/**
 * Diff a desired-state manifest against the current lock to produce a list
 * of operations. Pure function — no I/O, no side effects.
 *
 * Bug 1 fix: Merged files (package.json, .gitignore, CLAUDE.md, AGENTS.md) are
 * always SKIP'd. They are managed by init's merge flow, not update.
 */
export function diffDesiredState(
  lock: KdocLock,
  desired: DesiredStateManifest,
): DiffOperation[] {
  const ops: DiffOperation[] = [];

  const templateToLockPath = new Map<string, string>();
  for (const [path, entry] of Object.entries(lock.files)) {
    templateToLockPath.set(entry.template, path);
  }

  const matchedLockPaths = new Set<string>();

  for (const [desiredPath, desiredEntry] of Object.entries(desired)) {
    const lockEntry = lock.files[desiredPath];

    if (lockEntry) {
      matchedLockPaths.add(desiredPath);

      // Bug 1 fix: Merged entries are managed by init's merge flow — always skip
      if (lockEntry.action === 'merged') {
        ops.push({ type: 'SKIP', path: desiredPath });
        continue;
      }

      if (lockEntry.action === 'created') {
        const templateChanged = lockEntry.templateHash !== desiredEntry.currentTemplateHash;
        if (!templateChanged) {
          ops.push({ type: 'SKIP', path: desiredPath });
          continue;
        }
        const userModified =
          desiredEntry.currentFileHash !== undefined &&
          desiredEntry.currentFileHash !== lockEntry.hash;
        ops.push({ type: 'UPDATE', path: desiredPath, template: desiredEntry.template, userModified });
      }
    } else {
      const oldPath = templateToLockPath.get(desiredEntry.template);
      if (oldPath && !matchedLockPaths.has(oldPath)) {
        matchedLockPaths.add(oldPath);
        const oldEntry = lock.files[oldPath];
        const userModified =
          oldEntry.action === 'created' &&
          desiredEntry.currentFileHash !== undefined &&
          desiredEntry.currentFileHash !== oldEntry.hash;
        ops.push({
          type: 'RENAME',
          oldPath,
          newPath: desiredPath,
          template: desiredEntry.template,
          userModified,
        });
      } else {
        ops.push({ type: 'CREATE', path: desiredPath, template: desiredEntry.template });
      }
    }
  }

  for (const [lockPath, lockEntry] of Object.entries(lock.files)) {
    if (!matchedLockPaths.has(lockPath)) {
      // Bug 1 fix: Never REMOVE merged files — they have user content
      if (lockEntry.action === 'merged') {
        ops.push({ type: 'SKIP', path: lockPath });
      } else {
        ops.push({ type: 'REMOVE', path: lockPath, userModified: false });
      }
    }
  }

  return ops;
}

// ---- Executor ----

function backupFile(projectDir: string, relativePath: string): void {
  const absSource = join(projectDir, relativePath);
  const absDest = join(projectDir, '.kdoc.backup', relativePath);
  if (!existsSync(absSource)) return;
  if (existsSync(absDest)) return;
  ensureDir(dirname(absDest));
  copyFileSync(absSource, absDest);
}

interface ExecuteUpdateResult {
  created: string[];
  updated: string[];
  removed: string[];
  renamed: Array<{ from: string; to: string }>;
  skipped: string[];
  errors: Array<{ path: string; error: string }>;
}

/**
 * Build default render values for template rendering.
 * Bug 2 fix: Templates must be piped through the renderer before writing.
 */
export function buildRenderValues(config: KdocConfig, projectDir?: string): Record<string, string> {
  const resolvedDir = projectDir ?? process.env.KDOC_PROJECT_DIR ?? process.cwd();
  return {
    PROJECT_NAME: basename(resolvedDir) || 'Project',
    KNOWLEDGE_ROOT: config.root ?? 'Knowledge',
    SCOPE: 'root',
    DATE: new Date().toISOString().slice(0, 10),
    WIKILINK_PREFIX: '',
  };
}

async function executeUpdate(
  ops: DiffOperation[],
  lock: KdocLock,
  projectDir: string,
  config: KdocConfig,
  templateResolver: (templateName: string) => { sourcePath: string; content: string } | null,
  opts: { force?: boolean; yes?: boolean },
): Promise<ExecuteUpdateResult> {
  const result: ExecuteUpdateResult = {
    created: [],
    updated: [],
    removed: [],
    renamed: [],
    skipped: [],
    errors: [],
  };

  const updatedLock: KdocLock = {
    ...lock,
    files: { ...lock.files },
    kdocVersion: getKdocVersion(),
    updatedAt: new Date().toISOString(),
  };

  const renderValues = buildRenderValues(config, projectDir);

  for (const op of ops) {
    try {
      if (op.type === 'SKIP') {
        result.skipped.push(op.path);
        continue;
      }

      if (op.type === 'CREATE') {
        const resolved = templateResolver(op.template);
        if (!resolved) {
          result.errors.push({ path: op.path, error: `Template not found: ${op.template}` });
          continue;
        }
        // Bug 2 fix: render template placeholders before writing
        const { content: rendered } = renderTemplate(resolved.content, renderValues);
        const absPath = join(projectDir, op.path);
        safeWriteFile(absPath, rendered);
        const fileHash = hashString(rendered);
        const templateHash = hashString(resolved.content);
        updatedLock.files[op.path] = {
          action: 'created',
          hash: fileHash,
          templateHash,
          template: op.template,
        };
        result.created.push(op.path);
        continue;
      }

      if (op.type === 'UPDATE') {
        if (op.userModified && !opts.force) {
          result.skipped.push(op.path);
          continue;
        }

        const resolved = templateResolver(op.template);
        if (!resolved) {
          result.errors.push({ path: op.path, error: `Template not found: ${op.template}` });
          continue;
        }

        if (op.userModified) {
          backupFile(projectDir, op.path);
        }

        // Bug 2 fix: render template placeholders before writing
        const { content: rendered } = renderTemplate(resolved.content, renderValues);
        const absPath = join(projectDir, op.path);
        safeWriteFile(absPath, rendered);
        const fileHash = hashString(rendered);
        const templateHash = hashString(resolved.content);
        updatedLock.files[op.path] = {
          action: 'created',
          hash: fileHash,
          templateHash,
          template: op.template,
        };
        result.updated.push(op.path);
        continue;
      }

      if (op.type === 'REMOVE') {
        const absPath = join(projectDir, op.path);
        if (existsSync(absPath)) {
          const lockEntry = lock.files[op.path];
          if (lockEntry?.action === 'created') {
            try {
              const currentHash = hashFile(absPath);
              if (currentHash !== lockEntry.hash && !opts.force) {
                result.skipped.push(op.path);
                continue;
              }
              if (currentHash !== lockEntry.hash) {
                backupFile(projectDir, op.path);
              }
            } catch {
              result.skipped.push(op.path);
              continue;
            }
          }
          unlinkSync(absPath);
        }
        delete updatedLock.files[op.path];
        result.removed.push(op.path);
        continue;
      }

      if (op.type === 'RENAME') {
        if (op.userModified && !opts.force) {
          result.skipped.push(op.oldPath);
          continue;
        }

        const resolved = templateResolver(op.template);
        if (!resolved) {
          result.errors.push({ path: op.newPath, error: `Template not found: ${op.template}` });
          continue;
        }

        const absOld = join(projectDir, op.oldPath);
        const absNew = join(projectDir, op.newPath);

        if (op.userModified) {
          backupFile(projectDir, op.oldPath);
        }

        ensureDir(dirname(absNew));
        if (existsSync(absOld)) {
          renameSync(absOld, absNew);
        }
        // Bug 2 fix: render template placeholders before writing
        const { content: rendered } = renderTemplate(resolved.content, renderValues);
        safeWriteFile(absNew, rendered);

        delete updatedLock.files[op.oldPath];
        const fileHash = hashString(rendered);
        const templateHash = hashString(resolved.content);
        updatedLock.files[op.newPath] = {
          action: 'created',
          hash: fileHash,
          templateHash,
          template: op.template,
        };
        result.renamed.push({ from: op.oldPath, to: op.newPath });
        continue;
      }
    } catch (err) {
      const path = 'path' in op ? (op as { path: string }).path :
        'newPath' in op ? (op as { newPath: string }).newPath : 'unknown';
      const message = err instanceof Error ? err.message : String(err);
      result.errors.push({ path, error: message });
    }
  }

  writeLock(projectDir, updatedLock);

  return result;
}

// ---- Retrofit Intent ----

function parseYamlFrontmatter(content: string): { frontmatter: string; body: string; hasFrontmatter: boolean } {
  const match = content.match(/^---\n([\s\S]*?)\n---\n?([\s\S]*)$/);
  if (!match) return { frontmatter: '', body: content, hasFrontmatter: false };
  return { frontmatter: match[1], body: match[2], hasFrontmatter: true };
}

function hasIntentField(frontmatter: string): boolean {
  return /^intent\s*:/m.test(frontmatter);
}

function hasWhySection(body: string): boolean {
  return /^##\s+(Why|Rationale)\b/m.test(body);
}

function addIntentToFrontmatter(frontmatter: string): string {
  const lines = frontmatter.split('\n');
  lines.push('intent: ""');
  return lines.join('\n');
}

function addWhySection(body: string): string {
  const lines = body.split('\n');
  let insertIndex = -1;

  for (let i = 0; i < lines.length; i++) {
    if (/^#\s+/.test(lines[i])) {
      insertIndex = i + 1;
      break;
    }
  }

  const whyBlock = [
    '',
    '## Why',
    '',
    '> TODO: Describe why this exists and what intent it serves.',
    '',
  ];

  if (insertIndex >= 0) {
    lines.splice(insertIndex, 0, ...whyBlock);
  } else {
    lines.unshift(...whyBlock);
  }

  return lines.join('\n');
}

async function retrofitIntent(projectDir: string, config: KdocConfig, dryRun: boolean): Promise<{ modified: string[]; skipped: string[] }> {
  const root = config.root ?? 'Knowledge';
  const knowledgeDir = join(projectDir, root);

  if (!existsSync(knowledgeDir)) {
    console.log(`No Knowledge directory found at ${root}/`);
    return { modified: [], skipped: [] };
  }

  const mdFiles = fg.sync('**/*.md', {
    cwd: knowledgeDir,
    absolute: false,
    ignore: ['**/node_modules/**', '**/.obsidian/**'],
  });

  const modified: string[] = [];
  const skipped: string[] = [];

  for (const relPath of mdFiles) {
    const absPath = join(knowledgeDir, relPath);
    const content = readFileSync(absPath, 'utf8');
    const { frontmatter, body, hasFrontmatter } = parseYamlFrontmatter(content);

    if (!hasFrontmatter) {
      skipped.push(relPath);
      continue;
    }

    let newFrontmatter = frontmatter;
    let newBody = body;
    let changed = false;

    if (!hasIntentField(frontmatter)) {
      newFrontmatter = addIntentToFrontmatter(frontmatter);
      changed = true;
    }

    if (!hasWhySection(body)) {
      newBody = addWhySection(body);
      changed = true;
    }

    if (changed) {
      if (!dryRun) {
        const newContent = `---\n${newFrontmatter}\n---\n${newBody}`;
        safeWriteFile(absPath, newContent);
      }
      modified.push(relPath);
    } else {
      skipped.push(relPath);
    }
  }

  return { modified, skipped };
}

// ---- Commander registration ----

export function registerUpdateCommand(program: Command): void {
  const cmd = new Command('update');

  cmd
    .description('Update scripts and templates to the current kdoc version')
    .option('--force', 'Overwrite user-modified files without prompting')
    .option('--dry-run', 'Show planned operations without executing them')
    .option('--yes', 'Non-interactive: skip prompts (conflicts default to Skip)')
    .option('--retrofit-intent', 'Add missing intent fields and ## Why sections to existing docs')
    .action(async (opts: { force?: boolean; dryRun?: boolean; yes?: boolean; retrofitIntent?: boolean }) => {
      const cwd = process.env.KDOC_PROJECT_DIR ?? process.cwd();

      const config = loadConfig(cwd);
      if (!config) {
        console.error('Error: .kdoc.yaml not found. Run `kdoc init` first.');
        process.exitCode = 2;
        return;
      }

      // Handle --retrofit-intent as a separate flow
      if (opts.retrofitIntent) {
        console.log('kdoc update: scanning for missing intent/rationale...');
        const { modified, skipped } = await retrofitIntent(cwd, config, opts.dryRun ?? false);

        if (opts.dryRun) {
          console.log(`\n[dry-run] Would modify ${modified.length} file(s):`);
          for (const f of modified) console.log(`  [MODIFY] ${f}`);
          console.log(`  Skipped: ${skipped.length} file(s) (already have intent or no frontmatter)`);
          console.log('\n[dry-run] No changes applied.');
        } else {
          console.log(`\nModified ${modified.length} file(s):`);
          for (const f of modified) console.log(`  [MODIFY] ${f}`);
          console.log(`Skipped: ${skipped.length} file(s)`);
        }
        return;
      }

      const lock = loadLock(cwd);
      if (!lock) {
        console.error('Error: .kdoc.lock not found. No installation found to update.');
        process.exitCode = 2;
        return;
      }

      const templateResolver = makeUpdateTemplateResolver();

      // Build desired state from current kdoc version + config
      const desired = buildDesiredState(config, cwd, templateResolver);
      const ops = diffDesiredState(lock, desired);

      if (opts.dryRun) {
        const nonSkipOps = ops.filter(o => o.type !== 'SKIP');
        console.log('kdoc update: planned operations:');
        for (const op of ops) {
          if (op.type === 'RENAME') {
            console.log(`  [${op.type.padEnd(6)}] ${op.oldPath} → ${op.newPath}`);
          } else {
            console.log(`  [${op.type.padEnd(6)}] ${(op as { path: string }).path}`);
          }
        }
        if (nonSkipOps.length === 0) console.log('  (no changes needed)');
        console.log('\n[dry-run] No changes applied.');
        return;
      }

      const nonSkipOps = ops.filter(o => o.type !== 'SKIP');

      // Always run pack/tool installers even when scaffold-managed files are current
      const packToolResult = { created: [] as string[], skipped: [] as string[], errors: [] as Array<{ path: string; error: string }> };
      for (const pack of config.packs ?? []) {
        const packResult = await installPackAssets(pack, cwd, config, { force: opts.force });
        packToolResult.created.push(...packResult.installed);
        packToolResult.skipped.push(...packResult.skipped);
        packToolResult.errors.push(...packResult.errors.map((error) => ({ path: pack, error })));
      }
      for (const tool of config.tools ?? []) {
        try {
          const toolResult = runToolInstaller(tool, cwd, { yes: opts.yes });
          packToolResult.created.push(...toolResult.manifest.created);
          packToolResult.skipped.push(...toolResult.manifest.skipped);
          for (const warning of toolResult.warnings) {
            console.warn(`Warning: ${warning}`);
          }
        } catch {
          // Tool installer not available or failed — continue without crashing
        }
      }

      if (nonSkipOps.length === 0 && packToolResult.created.length === 0 && packToolResult.errors.length === 0) {
        console.log('kdoc update: already up to date.');
        return;
      }

      // Execute scaffold operations
      const result = nonSkipOps.length > 0
        ? await executeUpdate(ops, lock, cwd, config, templateResolver, {
            force: opts.force,
            yes: opts.yes,
          })
        : { created: [], updated: [], skipped: [], merged: [], removed: [], renamed: [] as Array<{ from: string; to: string }>, errors: [] as Array<{ path: string; error: string }> };

      // Merge pack/tool results
      for (const path of packToolResult.created) {
        if (!result.created.includes(path)) result.created.push(path);
      }
      result.errors.push(...packToolResult.errors);

      // Report
      if (result.created.length > 0) {
        console.log(`Created ${result.created.length} file(s):`);
        for (const f of result.created) console.log(`  [CREATE] ${f}`);
      }
      if (result.updated.length > 0) {
        console.log(`Updated ${result.updated.length} file(s):`);
        for (const f of result.updated) console.log(`  [UPDATE] ${f}`);
      }
      if (result.removed.length > 0) {
        console.log(`Removed ${result.removed.length} file(s):`);
        for (const f of result.removed) console.log(`  [REMOVE] ${f}`);
      }
      if (result.renamed.length > 0) {
        console.log(`Renamed ${result.renamed.length} file(s):`);
        for (const r of result.renamed) console.log(`  [RENAME] ${r.from} → ${r.to}`);
      }
      if (result.skipped.length > 0) {
        console.log(`Skipped ${result.skipped.length} file(s) (user-modified, use --force to overwrite)`);
      }
      if (result.errors.length > 0) {
        console.error(`Errors (${result.errors.length}):`);
        for (const e of result.errors) console.error(`  [ERROR] ${e.path}: ${e.error}`);
        process.exitCode = 1;
      }

      console.log('kdoc update complete.');
    });

  program.addCommand(cmd);
}
